mapper.insert:
INSERT INTO 
	system_collect_file (
		id
		,name
		,pc_id
		,source_name
		,source_path
		,target_name
		,target_path
		,run
		,parsing_type_id
	)
VALUES (
	#{params.id}
	,#{params.name}
	,#{params.pcId}
	,#{params.sourceName}
	,#{params.sourcePath}
	,#{params.targetName}
	,#{params.targetPath}
	,#{params.run}
	,#{params.parsingTypeId}
)
ON DUPLICATE KEY UPDATE
	name = VALUES(name)
	,pc_id = VALUES(pc_id)
	,source_name = VALUES(source_name)
	,source_path = VALUES(source_path)
	,target_name = VALUES(target_name)
	,target_path = VALUES(target_path)
	,run = VALUES(run)
	,parsing_type_id = VALUES(parsing_type_id)

