UPDATE 
	dain_sensor_type_setting 
SET 
	group_order = #{params.group_order}
	,min_gauge = #{params.min_gauge}
	,max_gauge = #{params.max_gauge}
	,criteria_val1 = #{params.criteria_val1}
	,criteria_val2 = #{params.criteria_val2}
	,criteria_val3 = #{params.criteria_val3}
	,`interval` = #{params.interval}
	,hidden = #{params.hidden}
WHERE 
	id = #{params.id}

