INSERT INTO system_data_delete (
	id
	,sensor_id
	,del_point
	,target_column
	,start_dt
	,last_dt
	,run
)
VALUES (
	#{params.id}
	,#{params.sensorId}
	,#{params.delPoint}
	,#{params.targetColumn}
	,#{params.startDt}
	,#{params.lastDt}
	,#{params.run}
)
ON DUPLICATE KEY UPDATE
	sensor_id = VALUES(sensor_id)
	,del_point = VALUES(del_point)
	,target_column = VALUES(target_column)
	,start_dt = VALUES(start_dt)
	,last_dt = VALUES(last_dt)
	,run = VALUES(run)

mapper.select:
	SELECT 
		COUNT(*)
    FROM data_${params.place_code}
    WHERE 
    	measured_at >= #{params.from_dt}
    	AND sensor_id = #{params.sensor_id}

mapper.update:
UPDATE data_${params.place_code}
SET 
    initial_val = #{params.displace_val},
    changed_val = (displace_val - #{params.displace_val})
WHERE 
	measured_at >= #{params.from_dt}
	AND sensor_id = #{params.sensor_id}

UPDATE 
	data_${params.place} 
SET 
	correction_val = #{params.correction}
	,angle_val = #{params.angle}
	,displace_val = #{params.displace}
	,changed_val = #{params.changed}
WHERE 
	id = #{params.id}

UPDATE 
	data_${params.place} 
SET 
	used = false 
WHERE 
	id = #{params.id}

mapper.select:
SELECT 
	COUNT(*) 
FROM data_${params.place_code} 
WHERE 
	measured_at >= #{params.from_dt}

		AND measured_at <= #{params.to_dt}

	AND sensor_id = #{params.sensor_id}

mapper.update:
UPDATE data_${params.place_code} 
SET 

	    correction_val = ROUND(${params.execMap['correction'].calculation}, 3),


	    angle_val = ROUND(${params.execMap['angle'].calculation},3),


	    displace_val = ROUND(${params.execMap['displace'].calculation},3),

	changed_val = displace_val - initial_val
WHERE 
	measured_at >= #{params.from_dt}

		AND measured_at <= #{params.to_dt}

	AND sensor_id = #{params.sensor_id}
